## 2. REFERENCE VIEW ARCHITECTURE

**File:** `/Users/anotonio.silva/antonio/lol/src/components/snippet_manager/snippet_manager_view.tsx`

### Complete View Pattern Structure:

```typescript
interface Key Imports {
  - useState, useEffect, useCallback, useMemo for state management
  - Database access (snippetDb)
  - useDbSearch for full-text search
  - useNavigation for breadcrumbs
  - useAlert for confirmations
  - useHUD for toast notifications
  - useKeyboardShortcut for key bindings
  - List/ListItem/ListSection for rendering
  - SearchBar with dropdown filters
  - ActionPanel with keyboard shortcuts
  - Alert modal component
  - Form components (FormTextField, FormTextArea, etc.)
}
```

### State Management Pattern (lines 316-326)
```typescript
const [entries, setEntries] = useState<SnippetEntry[]>([]);
const [query, setQuery] = useState('');
const [filterValue, setFilterValue] = useState('all');
const [selectedIndex, setSelectedIndex] = useState(0);
const [actionsOpen, setActionsOpen] = useState(false);
const [subView, setSubView] = useState<SnippetSubView>('list' | 'create' | 'edit');
const [editingSnippet, setEditingSnippet] = useState<SnippetEntry | undefined>();
```

### Data Loading Pattern (lines 331-358)
```typescript
useEffect(() => {
  let aborted = false;

  snippetDb.getAll()
    .then(rows => {
      if (aborted) return;
      if (rows.length > 0) {
        setEntries(rows.map(rowToEntry));  // Convert DB rows to UI entries
      } else if (!isTauri) {
        // Mock data fallback for dev
        const mock = MOCK_SNIPPET_ENTRIES.map(e => ({ ...e }));
        setEntries(mock);
        Promise.all(mock.map(e => snippetDb.insert(entryToRow(e)))).catch(console.error);
      }
    })
    .catch(err => {
      console.error('Failed to load snippets:', err);
      if (!isTauri && !aborted) {
        setEntries(MOCK_SNIPPET_ENTRIES.map(e => ({ ...e })));
      }
    });

  return () => {
    aborted = true;  // Cancel pending operations
  };
}, []);
```

### Filtering & Grouping Pattern (lines 367-416)
```typescript
const filtered = useMemo(() => {
  let items = ftsResults ?? entries;

  // Apply category filter
  if (filterValue !== 'all') {
    items = items.filter(e => e.category === filterValue);
  }

  // Fallback to fuzzy search if no FTS results
  if (!ftsResults && query) {
    items = items.filter(e =>
      fuzzyMatch(query, e.name) ||
      fuzzyMatch(query, e.keyword) ||
      fuzzyMatch(query, e.content)
    );
  }
  return items;
}, [entries, query, filterValue, ftsResults]);

// Group by category
const groupedByCategory = useMemo(() => {
  const groups: { title: string; items: SnippetEntry[] }[] = [];
  const categoryOrder = ['code', 'email', 'template', 'general'] as const;

  for (const cat of categoryOrder) {
    const items = filtered.filter(e => e.category === cat);
    if (items.length > 0) {
      groups.push({ title: categoryLabels[cat]!, items });
    }
  }
  return groups;
}, [filtered]);
```

### Full-Text Search Integration (lines 360-365)
```typescript
const dbSearchFn = useCallback((q: string) => snippetDb.search(q), []);
const { results: ftsResults, invalidate: invalidateFts } = useDbSearch(
  query,
  dbSearchFn,
  rowToEntry  // Converter function
);
```

### CRUD Operations Pattern

**Create:** (lines 568-588)
```typescript
const newEntry: SnippetEntry = {
  id: crypto.randomUUID(),
  name: form.name,
  keyword: form.keyword,
  content: form.snippet,
  category: form.category,
  tags,
  createdAt: new Date(),
};
setEntries(prev => [newEntry, ...prev]);
snippetDb.insert(entryToRow(newEntry)).catch(console.error);
invalidateFts();
showHUD({ icon: <SnippetHUDIcon />, title: 'Snippet Created' });
```

**Update:** (lines 543-562)
```typescript
snippetDb.update(editingSnippet.id, {
  name: form.name,
  keyword: form.keyword,
  content: form.snippet,
  category: form.category,
  tags: JSON.stringify(tags),
}).catch(console.error);
invalidateFts();
```

**Delete with Confirmation:** (lines 487-531)
```typescript
confirmAlert({
  title: `Delete "${entryName}"?`,
  message: 'This snippet will be permanently deleted.',
  primaryAction: {
    label: 'Delete',
    style: 'destructive',
    onAction: () => {
      setEntries(prev => prev.filter(e => e.id !== entryId));
      snippetDb.delete(entryId).catch(console.error);
      invalidateFts();
      showHUD({ icon: <SnippetHUDIcon />, title: 'Deleted' });
    },
  },
});
```

### Keyboard Shortcut Binding Pattern (lines 615-668)
```typescript
useKeyboardShortcut(
  { key: 'k', meta: true },
  toggleActions,
  { enabled: subView === 'list' }  // Can disable conditionally
);
useKeyboardShortcut({ key: 'Escape' }, handleEscape, {
  enabled: subView !== 'list',
  preventDefault: false  // Let default Escape behavior work
});
```

### Action Panel with Dropdown (lines 670-748)
```typescript
const dropdownSections: DropdownSection[] = useMemo(
  () => [
    {
      title: 'Actions',
      actions: [
        {
          label: 'Insert',
          shortcut: <Kbd keys={['↵']} />,
          onClick: handleInsert,
        },
        {
          label: 'Copy',
          shortcut: <Kbd keys={['⌘', 'C']} />,
          onClick: handleCopy,
        },
      ],
    },
    {
      title: 'Danger Zone',
      actions: [
        {
          label: 'Delete',
          shortcut: <Kbd keys={['⌘', '⌫']} />,
          onClick: handleDelete,
        },
      ],
    },
  ],
  [selectedEntry?.content, handleInsert, handleEdit, handleDelete]
);
```

### Sub-View Rendering Pattern (lines 753-799)
For form views, render different content while keeping SearchBar and ActionPanel structure:
```typescript
if (subView !== 'list') {
  return (
    <>
      <SearchBar
        value=""
        onChange={() => {}}
        placeholder="Create/Edit Note"
        breadcrumbs={[...nav.breadcrumbs, { label: 'Notes', onBack: handleEscape }]}
      />
      <div className="command-palette__body">
        <div className="command-palette__list-container">
          <EditSnippetView snippet={editingSnippet} onSubmit={handleFormSubmit} />
        </div>
      </div>
      <ActionPanel contextLabel="Create/Edit" actions={[]} dropdownSections={[]} />
      <HUDContainer items={hudItems} />
    </>
  );
}
```

### List Rendering with Index Tracking (lines 835-883)
```typescript
<List
  itemCount={totalItemCount}
  onActiveIndexChange={handleActiveIndexChange}
  onAction={handleInsert}
>
  {(() => {
    let globalIndex = 0;
    const sections: ReactNode[] = [];

    for (const group of groupedByCategory) {
      sections.push(
        <ListSection key={group.title} title={group.title}>
          {group.items.map(entry => {
            const idx = globalIndex++;
            return (
              <ListItem
                key={entry.id}
                index={idx}
                icon={<SnippetHUDIcon />}
                title={entry.name}
                subtitle={truncateContent(entry.content, 50)}
                accessories={[
                  // Tags, dates, etc.
                ]}
                query={query || undefined}
              />
            );
          })}
        </ListSection>
      );
    }
    return sections;
  })()}
</List>
```

