export interface IconProps {
  size?: number;
  className?: string;
}

export function svgBase(props: IconProps) {
  const s = props.size ?? 16;
  return {
    width: s,
    height: s,
    viewBox: '0 0 16 16',
    xmlns: 'http://www.w3.org/2000/svg',
    className: props.className,
  };
}

