101→const TAG_COLOR_NAMES = new Set<string>(Object.keys(TAG_COLOR_HEX));
102→
103→function isTagColor(value: string): value is TagColor {
104→  return TAG_COLOR_NAMES.has(value);
105→}
106→
107→function rowToEntry(row: SnippetRow): SnippetEntry {
108→  const parsed = new Date(row.created_at);
109→  const createdAt = isNaN(parsed.getTime()) ? new Date() : parsed;
110→
111→  let tags: SnippetEntry['tags'] = [];
112→  try {
113→    const raw = JSON.parse(row.tags);
114→    if (Array.isArray(raw)) {
115→      tags = raw.map((t: {
116→        text?: string;
117→        color?: string;
118→      }) => ({
119→        text: typeof t.text === 'string' ? t.text : '',
120→        color:
121→          typeof t.color === 'string' && isTagColor(t.color)
122→            ? t.color
123→            : undefined,
124→      }));
125→    }
126→  } catch {
127→    // empty
128→  }
129→
130→  return {
131→    id: row.id,
132→    name: row.name,
133→    keyword: row.keyword,
134→    content: row.content,
135→    category: isSnippetCategory(row.category) ? row.category : 'general',
136→    tags,
137→    createdAt,
138→  };
139→}
140→
141→function entryToRow(entry: SnippetEntry): SnippetRow {
142→  return {
143→    id: entry.id,
144→    name: entry.name,
145→    keyword: entry.keyword,
146→    content: entry.content,
147→    category: entry.category,
148→    tags: JSON.stringify(entry.tags),
149→    created_at: entry.createdAt.toISOString(),
150→  };
151→}
152→
153→const FILTER_SECTIONS: SearchDropdownSection[] = [
154→  {
155→    options: [
156→      {
157→        label: 'All',
158→        value: 'all',
159→      },
160→    ],
161→  },
162→  {
163→    title: 'Category',
164→    options: SNIPPET_CATEGORIES.map(c => ({
165→      label: c.label,
166→      value: c.value,
167→    })),
168→  },
169→];
170→
171→interface SnippetFormState {
172→  name: string;
173→  keyword: string;
174→  snippet: string;
175→  category: SnippetCategory;
176→  tags: string[];
177→}
178→
179→const INITIAL_SNIPPET_FORM: SnippetFormState = {
180→  name: '',
181→  keyword: '',
182→  snippet: '',
183→  category: 'general',
184→  tags: [],
185→};
186→
187→const FORM_TAG_OPTIONS = SNIPPET_TAGS.map(t => ({
188→  label: t.label,
189→  value: t.value,
190→}));
191→
192→const FORM_CATEGORY_OPTIONS = SNIPPET_CATEGORIES.map(c => ({
193→  label: c.label,
194→  value: c.value,
195→}));
196→
197→interface EditSnippetViewProps {
198→  snippet?: SnippetEntry;
199→  onSubmit: (form: SnippetFormState) => void;
200→}
201→
202→function EditSnippetView({ snippet, onSubmit }: EditSnippetViewProps) {
203→  const [form, setForm] = useState<SnippetFormState>(() => {
204→    if (snippet) {
205→      return {
206→        name: snippet.name,
207→        keyword: snippet.keyword,
208→        snippet: snippet.content,
209→        category: snippet.category,
210→        tags: snippet.tags.map(t => t.text.toLowerCase()),
211→      };
212→    }
213→    return INITIAL_SNIPPET_FORM;
214→  });
215→  const [errors, setErrors] = useState<
216→    Partial<Record<keyof SnippetFormState, string>>
217→  >({});
218→
219→  const handleSubmit = useCallback(() => {
220→    const newErrors: Partial<Record<keyof SnippetFormState, string>> = {};
221→    if (!form.name.trim()) {
222→      newErrors.name = 'Name is required';
223→    }
224→    if (!form.snippet.trim()) {
225→      newErrors.snippet = 'Snippet content is required';
226→    }
227→    setErrors(newErrors);
228→    if (Object.keys(newErrors).length > 0) return;
229→    onSubmit(form);
230→  }, [
231→    form,
232→    onSubmit,
233→  ]);
234→
235→  useKeyboardShortcut(
236→    {
237→      key: 'Enter',
238→      meta: true,
239→    },
240→    handleSubmit,
241→  );
242→
243→  return (
244→    <Form onSubmit={handleSubmit}>
245→      <FormTextField
246→        label="Name"
247→        value={form.name}
248→        onChange={v =>
249→          setForm(prev => ({
250→            ...prev,
251→            name: v,
252→          }))
253→        }
